def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def travel_time(from_pos, to_pos):
        return np.linalg.norm(to_pos - from_pos) / truck_speed

    def waiting_penalty(arrive_time, window):
        if arrive_time < window[0]:
            return window[0] - arrive_time
        return 0

    def time_window_flexibility(arrival, window):
        if arrival < window[0]:
            return window[1] - window[0]
        elif arrival > window[1]:
            return float('inf')
        else:
            return window[1] - arrival

    costs = []
    flexibility_scores = []
    for i, customer_pos in enumerate(unvisited_customers):
        tt = travel_time(cur_truck_pos, customer_pos)
        arrival = current_time + tt
        wait_pen = waiting_penalty(arrival, time_windows[i])
        flex_score = time_window_flexibility(arrival, time_windows[i])
        total_time = tt + wait_pen
        costs.append(total_time)
        flexibility_scores.append(flex_score)

    # Dynamic scheduling factor calculation
    dynamic_weights = []
    for i in range(len(unvisited_customers)):
        future_flexibility_impact = 0
        for j in range(len(unvisited_customers)):
            if i != j:
                pos = unvisited_customers[j]
                future_arrival_time = current_time + travel_time(cur_truck_pos, pos) + costs[i]
                future_flexibility_impact += time_window_flexibility(future_arrival_time, time_windows[j])
        dynamic_weights.append(costs[i] * future_flexibility_impact)

    # Select best node based on smallest dynamic weight, considering both cost and future flexibility
    best_node = np.argmin(dynamic_weights)

    return best_node

