def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def travel_time(from_pos, to_pos):
        return np.linalg.norm(to_pos - from_pos) / truck_speed

    def time_window_fitness(arrive_time, window, buffer_penalty=5):
        if arrive_time > window[1]:
            return 1000 * (arrive_time - window[1])
        elif arrive_time < window[0]:
            return buffer_penalty * (window[0] - arrive_time)
        return 0

    scores = []
    for idx, customer in enumerate(unvisited_customers):
        customer_travel_time = travel_time(cur_truck_pos, customer)
        predicted_arrival_time = current_time + customer_travel_time
        penalty = time_window_fitness(predicted_arrival_time, time_windows[idx])

        cooperative_adjustment = 0
        for other_pos in all_truck_pos:
            if not np.array_equal(other_pos, cur_truck_pos):
                other_travel_time = travel_time(other_pos, customer)
                other_arrival_time = current_time + other_travel_time
                cooperative_adjustment += 0.1 * time_window_fitness(other_arrival_time, time_windows[idx], buffer_penalty=2)

        total_score = customer_travel_time + penalty - cooperative_adjustment
        scores.append(total_score)

    best_node = np.argmin(scores)
    return best_node

